"""
MKT Context Commentary — Genesis chapters 29–30
Run: python3 scripts/zc-context-genesis-29-30.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (prior chapters; merge_comm skips already-present entries)

Key decisions in this range:
- Ch29:v10 Jacob rolls the stone alone — communal wells required collective effort; Jacob's feat
  signals either extraordinary strength or divine empowerment at the moment of seeing Rachel
- Ch29:v14 "flesh and blood" (ʿaṣmî ûḇĕśārî) — this is a covenant-kinship formula, not mere
  sentiment; it recurs in Judg 9:2 and 2 Sam 5:1 as the basis for covenantal obligation
- Ch29:v17 Leah's "rakkôt" (soft/weak/tender) eyes — the Hebrew is ambiguous; LXX reads "good";
  the contrast with Rachel's beauty is clear but the precise deficiency is not
- Ch29:v25 Jacob's complaint uses mirmāh (deceit) — the same root as his own deception of Isaac
  in ch.27; the narrative's symmetry is deliberate
- Ch29:vv.32-35 Son naming speeches — each name embeds the theological drama (see/hear/attach/praise);
  Judah's etymology from yādāh (praise) is the climax that ends Leah's naming sequence
- Ch30:v14 mandrakes (dûdāʾîm) — Mandragora officinarum; associated with love and fertility in
  ANE medicine and folk belief; the irony is that Rachel gets the mandrakes but Leah conceives
- Ch30:vv.37-42 Jacob's breeding strategy — the peeled-rod technique reflects ANE folk genetics;
  Gen 31:10-12 retrospectively clarifies that a divine dream, not the branches, governed the outcome
- Ch30:v27 Laban's divination (niḥaštî) — acknowledges using divination; common ANE practice;
  notable that he credits YHWH for his prosperity despite this mixed religious household
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "29": {
    "1": '<p>"Jacob continued on his journey and came to the land of the eastern peoples" — <em>bĕnê-qeḏem</em> (sons/people of the east) is the biblical designation for the peoples of upper Mesopotamia and the Syrian steppe: the Aramaeans, and the inhabitants of the Haran/Paddan-Aram region. The phrase orients the reader geographically — Jacob has left the land of promise and entered the territory of his mother\'s extended family. The journey from Beersheba to Haran was approximately 450 miles, traveled alone.</p>',

    "2": '<p>"There he saw a well in the open country, with three flocks of sheep lying near it because the flocks were watered from that well. The stone over the mouth of the well was large" — a communal well shared by multiple flocks from the surrounding area was a standard feature of ANE pastoral life. The large stone covering the well mouth was a communal resource-management device: it prevented animals from falling in, reduced evaporation, and ensured that the well was only opened when the community gathered, preventing any single group from monopolizing the water. The detail that "three flocks" are waiting signals a community protocol governing shared access.</p>',

    "3": '<p>"When all the flocks were gathered there, the shepherds would roll the stone away from the well\'s mouth and water the sheep. Then they would return the stone to its place" — the protocol establishes that the stone was rolled communally (requiring coordinated effort), watering proceeded collectively, and the stone was replaced afterward. This was a fair-access system: no single flock could water before all others arrived. Jacob\'s single-handed rolling of the stone in v.10, which would ordinarily require the combined effort of the assembled shepherds, marks his action as extraordinary.</p>',

    "4": '<p>"Jacob asked the shepherds, \'My brothers, where are you from?\' \'We\'re from Haran\'" — Jacob\'s opening address (<em>ʾaḥay</em>, my brothers) is the customary greeting between fellow shepherds and travelers in the ANE. The identification of Haran as their origin confirms Jacob is in the right region — Haran is the city where Terah settled and where Nahor\'s extended family remained (Gen 11:31–32; 24:10).</p>',

    "5": '<p>"Do you know Laban, Nahor\'s grandson?" — Jacob identifies Laban through the genealogical line: Nahor (Abraham\'s brother) → Bethuel → Laban. In the ANE, identifying someone by lineage rather than by name alone was the standard social protocol; the family connection was the relevant social marker. The shepherds\' affirmative response confirms Jacob has reached the right community.</p>',

    "6": '<p>"Here comes his daughter Rachel with the sheep" — the providential timing mirrors the servant\'s encounter with Rebekah in ch.24: the woman appears before the inquiry is complete. Rachel is introduced as a shepherdess (<em>rōʿāh ṣōʾn ʾāḇîhā</em>, tending her father\'s sheep) — a normal occupation for women in pastoral ANE societies. Zipporah and her sisters are shepherdesses in Exod 2:16; the role was socially respectable for unmarried daughters in herding households.</p>',

    "7": '<p>"The sun is still high; it\'s not time for the flocks to be gathered" — Jacob\'s observation about the timing reveals his knowledge of shepherding customs. The gathering at the communal well typically happened at the end of the day, when the flocks were brought in from pasture. Watering in midday and releasing animals back to pasture would have been inefficient and unusual. Jacob\'s suggestion that the shepherds return the animals to pasture rather than waiting may be an attempt to be alone with Rachel when she arrives.</p>',

    "8": '<p>"We can\'t, until all the flocks are gathered and the stone has been rolled away from the well\'s mouth" — the shepherds\' reply confirms the communal protocol of v.3: the stone is a collective responsibility and cannot be moved until all parties are present. Their response is not laziness but adherence to the shared-access agreement. The explanation also sets up the contrast with Jacob\'s individual stone-rolling in v.10.</p>',

    "9": '<p>"Rachel came with her father\'s flock, for she tended them" — the narrator\'s explanatory note (<em>kî rōʿāh hîʾ</em>, for she was a shepherdess) underscores that Rachel\'s presence at the well is occupational, not coincidental. She is not there because she happened to be passing; she is the responsible caretaker of Laban\'s flock. The scene parallels ch.24:15-16, where Rebekah appeared at the well in her normal occupation (water-carrying) just as the servant prayed.</p>',

    "10": '<p>"He went over and rolled the stone away from the mouth of the well and watered his uncle\'s sheep" — Jacob\'s single-handed removal of the communal stone is a feat that would ordinarily require the collective effort of all the assembled shepherds (v.3). The narrative offers no explanation for how he accomplished it — possibly indicating extraordinary strength, possibly that the three flocks\' shepherds also helped when they saw his intent, or possibly a narrative signal of divine enabling. The sight of Rachel is the immediate cause: "when Jacob saw Rachel... he went over and rolled." The action bypasses the community protocol in an act of generous hospitality toward his kinsman\'s flock.</p>',

    "11": '<p>"Jacob kissed Rachel and began to weep aloud" — the kiss and weeping are standard ANE family-reunion gestures, not primarily romantic expressions at this stage. Gen 45:14–15 (Joseph weeping on his brothers\' necks), Gen 33:4 (Esau running to kiss Jacob), and Gen 46:29 (Joseph weeping on Israel\'s neck) all use the same elements — embrace, kiss, weeping — for family reunions after long separation. Jacob has traveled 450 miles alone; the sight of his kinswomen triggers the emotional release of arrival. The romantic dimension is present but secondary to the kinship reunion convention.</p>',

    "12": '<p>"He had told Rachel that he was a relative of her father and a son of Rebekah. So she ran and told her father" — Jacob identifies himself through both paternal kin connection (relative of Laban) and maternal line (son of Rebekah). Rebekah is the link — she is both Laban\'s sister and Jacob\'s mother. Rachel\'s running to tell her father mirrors Rebekah\'s running to tell her mother\'s household in 24:28 — both women function as messengers who activate the household\'s hospitality response.</p>',

    "13": '<p>"Laban heard the news about Jacob, his sister\'s son, he hurried to meet him. He embraced him and kissed him" — Laban\'s response to the news of a kinsman\'s arrival is appropriate ANE hospitality: the embrace (<em>ḥābaqqô</em>) and kiss (<em>wĕnaššaq-lô</em>) are the formal welcome gestures. Compare Laban\'s response in 24:29-30, where he also "hurried out" — but there, the text explicitly notes he was motivated by seeing gold jewelry on Rebekah. Here, only kinship is specified. Jacob has no gold; his reception is based on family connection alone.</p>',

    "14": '<p>"You are my own flesh and blood" (<em>ʿaṣmî ûḇĕśārî ʾāttāh</em>) — this is a formal covenant-kinship declaration, not mere sentiment. The formula <em>ʿeṣem ûbāśār</em> (bone and flesh) appears in Judg 9:2 (Shechem\'s citizens claiming kinship-obligation to Abimelech) and 2 Sam 5:1 (Israel\'s tribes declaring covenant-kinship to David). Laban is formally acknowledging the kinship bond that creates mutual obligations. "After Jacob had stayed with him for a whole month" — a month of hospitality before business discussions reflects ANE social convention: guests were received before formal negotiations about labor or wages began.</p>',

    "15": '<p>"Just because you are a relative of mine, should you work for me for nothing?" — Laban\'s question opens the formal wage negotiation. In the ANE, a kinsman who worked within a household was not automatically exempt from wages simply because of the family connection; there was a recognized distinction between a guest being hosted and a worker providing ongoing labor. Laban\'s question formally acknowledges Jacob\'s work and invites Jacob to name what he wants — shifting the relationship from hospitality to economic exchange.</p>',

    "16": '<p>"Laban had two daughters; the name of the older was Leah, and the name of the younger was Rachel" — the narrator introduces the daughters with their birth-order prominently stated (older/younger). Birth order has been a recurring theme in Genesis — Cain/Abel, Ishmael/Isaac, Esau/Jacob — and the naming of the older before the younger here sets up the tension that will produce Laban\'s deception in v.26. The names: <em>Lēʾāh</em> (possibly "wild cow" or "weary") and <em>Rāḥēl</em> (ewe/female sheep), both animal names common in the pastoral ANE world.</p>',

    "17": '<p>"Leah had soft eyes, but Rachel had a lovely figure and was beautiful" — Leah\'s eyes are described as <em>rakkôt</em> (soft, tender, delicate). The LXX translates this as "weak" in the sense of not impressive; some interpreters read "gentle" or "lovely" as a positive quality. The contrast with Rachel\'s beauty is clear regardless of the precise connotation. In the ANE honor-shame context, physical attractiveness was a social asset affecting marriage prospects, and the narrator\'s comparison establishes why Jacob\'s preference for Rachel is intelligible within ANE expectations.</p>',

    "18": '<p>"I\'ll work for you seven years in return for your younger daughter Rachel" — Jacob proposes bride service as the substitute for the <em>mohar</em> (bride price). In the ANE, a man without the resources to pay a bride price could substitute a period of labor service for his prospective father-in-law. Nuzi tablets from upper Mesopotamia (near Haran, 14th century BCE) document similar arrangements where a man without means would serve as an "adopted son" in the household and receive a daughter in marriage. Seven years is a round number suggesting completion and full payment — not an arbitrary period but the equivalent of a substantial bride price.</p>',

    "19": '<p>"It\'s better that I give her to you than to some other man" — Laban\'s agreement is framed as endogamous preference: better to keep the marriage within the kinship network than to give Rachel to an outsider. This reflects the ANE value of endogamy — marrying within the clan or tribe — which preserved family property and social networks. The response also subtly positions Laban as doing Jacob a favor, a framing that will serve Laban later when he claims the right to control the terms of the arrangement.</p>',

    "20": '<p>"They seemed like only a few days to him because of his love for her" — one of the most celebrated paradoxes in Genesis. The usual effect of time in labor is that it feels long; Jacob\'s love for Rachel inverts this. The phrase marks seven years as the background to what the narrative will cover in a single verse, yet makes the emotional weight of that period — love sustained through labor — palpable. The compressed timeline also sets up the shock of v.25: after seven years of patient, love-driven service, the morning after the consummation reveals the deception.</p>',

    "21": '<p>"Give me my wife. My time is completed, and I want to make her my wife" — Jacob\'s demand is formal and contractual: the seven years are complete, the labor has been performed, the wage is due. "Give me my wife" (<em>hāḇāh ʾet-ʾištu</em>) uses the standard Hebrew idiom for completing a marriage transfer. Jacob has fulfilled his half of the agreement; he is now calling for Laban to fulfill his. The language is not romantic but legal — Jacob is claiming what the contract specifies.</p>',

    "22": '<p>"Laban brought together all the people of the place and gave a feast" — the wedding feast (<em>mišteh</em>) gathered the community (<em>kol-ʾanšê hammāqôm</em>). ANE wedding celebrations typically lasted seven days (v.27: "finish this daughter\'s bridal week"); they were public community events, not private ceremonies. The community gathering is also relevant to the deception: with the community present, the substitution of Leah for Rachel would require community complicity or at least the kind of darkness and veiling that prevented recognition.</p>',

    "23": '<p>"But when evening came, he took his daughter Leah and brought her to Jacob, and Jacob made love to her" — the deception operates through the darkness and the bridal veil (cf. 24:65, where Rebekah veiled herself when she saw Isaac). ANE bridal practice required the bride to be veiled throughout the wedding feast and the first night; the man would not see her face until the following morning. The seven-day feast was presumably accompanied by wine, further reducing Jacob\'s capacity to detect the substitution. Laban\'s agency is clear: "he took... he brought" — Laban is the actor, not Leah.</p>',

    "24": '<p>(Laban gave his servant Zilpah to his daughter as her attendant.) — The narrator\'s parenthetical note about Zilpah anticipates her role in ch.30:9-13, when Leah will give Zilpah to Jacob as a surrogate wife. Providing a maidservant as an attendant with the bride was an ANE marriage custom — the bride brought a domestic attendant who would serve her in her new household. Nuzi texts and other ANE sources confirm this practice; the attendant was understood as the bride\'s property within the new household.</p>',

    "25": '<p>"When morning came, there was Leah!" — the morning revelation is the narrative\'s hinge. The single sentence <em>wĕhinnēh-hîʾ Lēʾāh</em> (and behold, she was Leah) delivers the shock Jacob experiences. "What is this you have done to me?" — Jacob\'s complaint uses <em>mah-zōʾt ʿāśîtā lî</em> (what is this you have done to me), the same formula used by Pharaoh to Abraham (12:18), Isaac to Abimelech (26:10), and Abimelech to Jacob himself (ch.26) — a formula of moral accusation for a deception. The reader has already noted, in ch.27, that Jacob deceived his blind father using his brother\'s garments; here he is deceived by darkness and his wife\'s veil.</p>',

    "26": '<p>"It is not our custom here to give the younger daughter in marriage before the older one" — Laban\'s defense invokes social convention (<em>kēn yēʿāśeh bimqōmēnû</em>, thus it is done in our place). Birth-order priority in marriage was a recognized ANE custom, though not universal. Laban may have had this objection from the start but chose not to raise it when Jacob made his offer, instead waiting to exploit it at the moment of maximum vulnerability. The irony is precise: Jacob, who violated his own family\'s birth-order convention by stealing Esau\'s firstborn blessing, now finds the same convention invoked against him.</p>',

    "27": '<p>"Finish this daughter\'s bridal week; then we will give you the younger one also, in return for another seven years of work" — the "bridal week" (<em>šĕbūaʿ zōʾt</em>) is the seven-day wedding celebration period. Samson\'s wedding feast in Judg 14:12 is also a seven-day feast. The completion of Leah\'s wedding week before Rachel is given to Jacob was a social obligation — abandoning Leah\'s feast would have been a public disgrace. Laban\'s counter-offer requires another seven years of service — doubling Jacob\'s total obligation to fourteen years (7+7) in exchange for two wives.</p>',

    "28": '<p>"Jacob did so. He finished the week with Leah, and then Laban gave him his daughter Rachel to be his wife" — Jacob receives Rachel at the completion of Leah\'s wedding week, not at the completion of the second seven years. This is an important detail: Jacob is given both wives before the second service period begins, rather than waiting another seven years. Laban has secured fourteen years of labor but disbursed both daughters upfront — he has taken the risk that Jacob might leave after receiving Rachel without completing the second term.</p>',

    "29": '<p>(Laban gave his servant Bilhah to his daughter Rachel as her attendant.) — Parallel to Zilpah given to Leah (v.24), Laban provides Bilhah as Rachel\'s attendant and household servant within the new marital arrangement. Bilhah will become the mother of Dan and Naphtali through Rachel\'s surrogate arrangement in ch.30:3-8. The two attendants — Zilpah with Leah, Bilhah with Rachel — will function as the mothers of four of Jacob\'s twelve sons.</p>',

    "30": '<p>"His love for Rachel was greater than his love for Leah. And he worked for Laban another seven years" — the narrator states plainly the emotional asymmetry that will define the household\'s dynamics for the next decade. The phrase "greater than his love for Leah" does not specify what Jacob\'s relationship with Leah was — only that it was less. In the ANE context of polygynous households, differential love was a recognized social problem that law codes sometimes attempted to address (e.g., Deut 21:15-17 addresses the rights of the firstborn son of an unloved wife).</p>',

    "31": '<p>"When the LORD saw that Leah was not loved, he enabled her to conceive, but Rachel remained childless" — YHWH\'s intervention in the wives\' fertility follows the pattern established with Sarah (21:1) and Rebekah (25:21): the barrenness of the beloved or covenant-significant wife, and the opening of the womb as divine act. Here the pattern is inverted: the unloved wife is given fertility as divine compensation, while the loved wife remains barren. The divine response to Leah\'s situation is a form of covenant justice — YHWH sees what is hidden from human view and intervenes to correct the social imbalance.</p>',

    "32": '<p>"She named him Reuben, for she said, \'It is because the LORD has seen my misery. Surely my husband will love me now\'" — the naming speech encodes both the etymology and the theological significance. <em>Rĕʾûbēn</em> is parsed as <em>rāʾāh... bĕʿānyî</em> (he has seen my affliction) — the seeing of YHWH. Alternatively, the name reads as <em>rĕʾû bēn</em> (see, a son!). Both meanings are in play. Leah\'s hope — "surely my husband will love me now" (<em>yĕʾehāḇanî ʾîšî</em>) — establishes the emotional register that all four of her naming speeches will inhabit: she is giving sons in the hope of earning Jacob\'s affection.</p>',

    "33": '<p>"Because the LORD heard that I am not loved, he gave me this one too. So she named him Simeon" — <em>Šimʿôn</em> from <em>šāmaʿ</em> (to hear): YHWH has heard. The shift from sight (Reuben) to hearing (Simeon) traces two of YHWH\'s primary modes of engagement with human suffering — he both sees and hears the afflicted. The pattern mirrors Hagar\'s experience in 16:7-13, where YHWH both heard (<em>šāmaʿ</em>) her crying and appeared to her. Leah identifies herself as being in an analogous position to the other marginalized women in these narratives.</p>',

    "34": '<p>"Now at last my husband will become attached to me, because I have borne him three sons. So he was named Levi" — <em>Lēwî</em> from <em>lāwāh</em> (to cling, to be attached, to join): "now my husband will cling/attach to me." The clan of Levi — Israel\'s priestly tribe — receives its name from the verb of attachment. The irony of the name will become apparent in later history: the Levites will be "attached" not to a territorial allotment but to YHWH himself (Num 18:2-4). Leah\'s prayer for marital attachment becomes the name of the tribe that will be uniquely attached to divine service.</p>',

    "35": '<p>"This time I will praise the LORD. So she named him Judah. Then she stopped having children" — <em>Yĕhûḏāh</em> from <em>yādāh</em> (to praise, to give thanks): "this time I will praise YHWH." The fourth son\'s naming speech is the only one not oriented toward Jacob\'s affection — Leah turns instead to pure divine praise. The shift is theologically significant: after three sons named in the context of seeking her husband\'s love, the fourth is named in praise of YHWH alone. Judah will become the covenant tribe — the line of David and of Christ — and his name embeds the act of praise that becomes Israel\'s covenant response to YHWH.</p>',
  },
  "30": {
    "1": '<p>"Give me children, or I\'ll die!" — Rachel\'s demand to Jacob reflects the ANE social reality of barrenness: a woman who did not bear children lacked the primary social function for which marriage was contracted, and faced social marginalization, potential divorce, and the shame of being seen as divinely disfavored. "Or I\'ll die" is not hyperbole in the ANE context — it is a statement of social death: a woman without sons had no secure place in the household or in the community. Rachel\'s barrenness mirrors that of Sarah (ch.16) and Rebekah (ch.25), establishing the pattern of covenant-matriarch barrenness overcome by divine intervention.</p>',

    "2": '<p>"Am I in the place of God, who has kept you from having children?" — Jacob\'s anger at Rachel\'s demand is the only moment in the patriarchal narratives where a husband explicitly identifies God as the cause of his wife\'s barrenness. The theologically significant response attributes the closed womb directly to divine agency (<em>ʾĕlōhîm ʾăšer mānnaʿ mimmēkh pĕrî-bāṭen</em>), not to medical cause or human fault. Jacob is correct, though the attribution increases Rachel\'s frustration — she cannot bargain with God the way she can bargain with Jacob.</p>',

    "3": '<p>"Here is Bilhah, my servant. Sleep with her so that she can bear children for me and I too can have a family through her" — the surrogate wife arrangement Rachel proposes is documented in ANE legal texts from Nuzi (upper Mesopotamia, 14th century BCE) and from Old Babylonian law. A barren wife could give her personal maidservant (<em>šiphḥāh</em>) to her husband; any children born would be legally and socially attributed to the mistress. The Nuzi tablets include specific clauses in marriage contracts requiring a barren wife to provide her husband with a substitute. Rachel is acting within a recognized legal framework, not improvising.</p>',

    "4": '<p>"So she gave him her servant Bilhah as a wife. Jacob slept with her" — Bilhah receives the status of wife (<em>lĕ-ʾiššāh</em>) in this arrangement, not merely concubine — a distinction that grants her children full legal standing within the household. The parallel to Sarah\'s arrangement with Hagar (16:3) is exact: the same language, the same legal framework, the same potential for social conflict. The narrator does not comment on the ethics; the practice was legally and socially recognized.</p>',

    "5": '<p>"She became pregnant and bore him a son" — the conciseness of the announcement is in contrast with Leah\'s emotional naming speeches. Bilhah\'s pregnancy is a legal and social event within the surrogate arrangement; the emotional response belongs to Rachel, who names the child in the following verse.</p>',

    "6": '<p>"God has vindicated me; he has listened to my plea and given me a son. Because of this she named him Dan" — <em>Dān</em> from <em>dānannî ʾĕlōhîm</em> (God has judged/vindicated me). The root <em>dyn</em> (to judge, to vindicate, to exercise legal right) gives the tribe of Dan its name. Rachel\'s language of vindication is legal: God has acted as judge in her case, ruling in her favor against the implicit verdict of barrenness. The tribe of Dan will later produce the judge Samson (Judg 13:2), whose name and function echo this founding vocabulary.</p>',

    "7": '<p>"Rachel\'s servant Bilhah conceived again and bore Jacob a second son" — the second surrogate birth through Bilhah proceeds without the emotional elaboration of the first. The pattern of the surrogate arrangement is being established: two sons through Bilhah (parallel to Leah\'s four), which will be balanced by two sons through Zilpah.</p>',

    "8": '<p>"I have had a great struggle with my sister, and I have won. So she named him Naphtali" — <em>Naptālî</em> from <em>niptaltî ʾĕlōhîm</em> (I have wrestled/struggled with God) or from <em>pāthal</em> (to twist, to wrestle). The naming speech frames the surrogate births as a competitive contest with Leah. The word "struggle" (<em>niptaltî</em>) anticipates Jacob\'s wrestling at Peniel in ch.32 — the same root (<em>pāthal</em>) appears in the name Israel\'s founder will receive. Rachel\'s competitive framing reveals both her desperation and the household\'s underlying dynamics.</p>',

    "9": '<p>"When Leah saw that she had stopped having children, she took her servant Zilpah and gave her to Jacob as a wife" — Leah\'s entry into the surrogate competition mirrors Rachel\'s move. Having temporarily stopped conceiving, Leah responds in kind by offering Zilpah. The two-maidservant strategy escalates the childbearing contest from two wives to four mothers. ANE law recognized this competitive dynamic — some Nuzi marriage contracts specified that if a wife gave her husband a surrogate, the surrogate could not be replaced by the wife if the surrogate bore children.</p>',

    "10": '<p>"Leah\'s servant Zilpah bore Jacob a son" — the birth is stated without elaboration; the naming speech follows in v.11. The brevity contrasts with the emotional weight of the Leah-naming speeches in ch.29; Zilpah\'s births are presented as tactical moves in the household competition rather than moments of personal theological reflection.</p>',

    "11": '<p>"What good fortune! So she named him Gad" — <em>Gāḏ</em> is interpreted as deriving from <em>gāḏ</em> (good fortune, a troop). Leah\'s exclamation "what good fortune!" (<em>bāgāḏ</em> or <em>bĕgāḏ</em>) reflects the tactical win in the birth competition. Gad will become the name of the tribe known for its military prowess (Deut 33:20-21), and the word <em>gāḏ</em> was also the name of the Canaanite fortune god — giving the tribal name an ambiguous religious valence that the later prohibition of fortune-worship (Isa 65:11) may address.</p>',

    "12": '<p>"Leah\'s servant Zilpah bore Jacob a second son" — the second birth through Zilpah is narrated as concisely as the first, with the naming in v.13. The paired structure of the surrogate births (two through Bilhah, two through Zilpah) gives the four "handmaid\'s sons" a symmetric narrative form.</p>',

    "13": '<p>"How happy I am! The women will call me happy. So she named him Asher" — <em>ʾĀšēr</em> from <em>ʾāšar</em> (to be blessed, to call happy): "women will call me happy/blessed." The social dimension of the naming is significant: Leah\'s happiness is not merely personal but publicly validated — "the women" (<em>bānôt</em>, daughters) of the community will recognize her blessed status. The tribe of Asher is associated with blessing in the later tribal poetry (Deut 33:24-25; Gen 49:20).</p>',

    "14": '<p>"During wheat harvest, Reuben went out into the fields and found some mandrake plants, which he brought to his mother Leah" — mandrakes (<em>dûdāʾîm</em>) are Mandragora officinarum, a plant with a thick root that sometimes resembles a human figure. In ANE folk medicine and culture, mandrakes were associated with love, sexual potency, and fertility; the plant\'s name shares a root with <em>dôd</em> (beloved, love; Song of Songs 1:2). The Song of Songs 7:13 mentions mandrakes as part of a lover\'s invitation. Their appearance at wheat harvest (late spring) is botanically accurate — mandrakes bear fruit in April–May in the Levant.</p>',

    "15": '<p>"Wasn\'t it enough that you took away my husband? Will you take my son\'s mandrakes too?" — Leah\'s accusation that Rachel "took away" her husband reflects the social reality of the polygynous household: Jacob\'s time was a resource that both wives competed for. The exchange Leah offers — mandrakes for a night with Jacob — reveals how far the domestic arrangement has deteriorated: the wives are negotiating over the husband\'s presence as if he were a commodity. The irony of the exchange is that Rachel receives the fertility plant but it is Leah who conceives (vv.17-18).</p>',

    "16": '<p>"I have hired you with my son\'s mandrakes" — Leah\'s language is explicitly transactional: <em>śākōr śĕkhartîkhā</em> (I have hired you with wages), the same root used for hired labor. Jacob is described as being "hired" — he is spoken of as an economic transaction between the two wives. The scene reduces the household to its competitive dynamics: wives negotiating for time with their shared husband using agricultural products as currency. Jacob\'s response is silent compliance; he goes to Leah\'s tent that evening.</p>',

    "17": '<p>"God listened to Leah, and she became pregnant and bore Jacob a fifth son" — God\'s response to Leah is noted separately from the mandrake exchange: the divine hearing (<em>wayyišmaʿ ʾĕlōhîm ʾel-Lēʾāh</em>) is attributed to prayer or disposition, not to the mandrakes. The narrator does not credit the mandrakes with the fertility; the divine hearing is the cause. This implicitly comments on the mandrake transaction: the folk-magic remedy was irrelevant; YHWH\'s attention to Leah was the determining factor.</p>',

    "18": '<p>"God has rewarded me for giving my servant to my husband. So she named him Issachar" — <em>Yiśśākhār</em> from <em>śākhār</em> (hire, wages, reward): "God has given me my wages." Leah\'s naming connects Issachar\'s birth to the mandrake exchange (she "hired" Jacob) and to the surrogate arrangement (she gave Zilpah). The interpretive instability in the naming speech — was the "hire" the mandrakes, or the maidservant? — reflects the compressed moral complexities of the household. The tribe of Issachar is associated with agricultural wisdom and service (Gen 49:14-15; Deut 33:18-19).</p>',

    "19": '<p>"Leah conceived again and bore Jacob a sixth son" — Leah\'s sixth biological son (eighth counting the two surrogate births) signals the climax of her fertility. No other wife in the OT patriarchal narratives bears as many children as Leah; her fruitfulness is presented as the primary expression of YHWH\'s covenantal justice in the household — compensating the unloved wife with the thing the ANE household most valued.</p>',

    "20": '<p>"God has presented me with a precious gift. This time my husband will treat me with honor, because I have borne him six sons. So she named him Zebulun" — <em>Zĕḇûlûn</em> from <em>zāḇal</em> (to honor, to endow) or <em>zeḇed</em> (gift): "God has endowed me with a precious gift." Leah\'s hope returns to Jacob\'s honor (<em>yizbĕlēnî ʾîšî</em>, my husband will treat me with honor) — even after six sons, her primary longing is for her husband\'s recognition. The tribe of Zebulun is placed in a maritime or commercial context (Gen 49:13), occupying the northern lowland near the Sea of Galilee.</p>',

    "21": '<p>"Some time later she gave birth to a daughter and named her Dinah" — Dinah\'s birth is recorded without a naming speech or theological formula — the only birth in the sequence without one. This contrasts markedly with all twelve sons\' births and signals the patriarchal orientation of the genealogical record: daughters were not counted in the tribal enumeration. Dinah is named because she will be a significant character in ch.34 (the Shechem incident); her appearance here is a brief anticipatory note.</p>',

    "22": '<p>"Then God remembered Rachel; he listened to her and enabled her to conceive" — the divine "remembering" formula (<em>wayyizkōr ʾĕlōhîm ʾet-Rāḥēl</em>) is a technically precise theological term: God\'s <em>zākar</em> (remembering) is not forgetting-then-remembering but the divine act of attention and intervention in covenant faithfulness. The same formula appears in 8:1 (God remembered Noah in the ark) and 19:29 (God remembered Abraham when Lot was saved). The remembering of Rachel is the covenant-completion moment that the chapter has been building toward.</p>',

    "23": '<p>"She became pregnant and gave birth to a son and said, \'God has taken away my disgrace\'" — the word <em>ḥerpāh</em> (reproach, disgrace, shame) was the specific social stigma attached to barrenness. It appears also in 34:14 (the disgrace of giving a daughter to the uncircumcised), Isa 4:1 (the social shame of widowhood), and 1 Sam 1:6 (Hannah\'s rival who "provoked her severely" due to her barrenness). Rachel\'s barrenness was not merely a private grief but a public condition of social diminishment; its removal is the restoration of her full social standing.</p>',

    "24": '<p>"She named him Joseph, and said, \'May the LORD add to me another son\'" — <em>Yôsēp</em> from <em>ʾāsap</em> (to take away, v.23) and <em>yāsap</em> (to add): the name carries both a backward meaning (God has taken away my disgrace) and a forward meaning (may God add another son). The double etymology is the narrator\'s way of signaling that Joseph\'s story is not complete at birth — he will be the subject of extensive narrative in chs.37-50. Rachel\'s prayer ("may the LORD add another son") will be fulfilled in Benjamin\'s birth, but at the cost of Rachel\'s life (35:16-19).</p>',

    "25": '<p>"After Rachel gave birth to Joseph, Jacob said to Laban, \'Send me on my way so I can go back to my own homeland\'" — the birth of Joseph is the trigger for Jacob\'s departure request. With Rachel finally bearing a son, Jacob\'s primary reason for remaining in Haran (protecting and waiting for Rachel) has been satisfied. "My own homeland" (<em>limĕqômî ûlĕʾarṣî</em>, to my place and to my land) — Jacob uses the language of the promise; the land of Canaan is his covenantal home, to which YHWH pledged to return him (28:15).</p>',

    "26": '<p>"Give me my wives and children, for whom I have served you, and I will be on my way" — Jacob frames his request as the final fulfillment of the contracted service: he has worked fourteen years (7+7) for his wives; he is not running away but formally concluding the employment. "You know how much work I\'ve done for you" — Jacob\'s appeal to Laban\'s knowledge of his labor record is both a reminder and an implicit appeal to Laban\'s sense of obligation.</p>',

    "27": '<p>"I have learned by divination that the LORD has blessed me because of you" — <em>niḥaštî</em> (I have divined/learned by omens) acknowledges the use of divination — a common ANE practice involving observation of animal livers (hepatoscopy), oil on water, or celestial signs. Laban\'s admission that he uses divination is consistent with the mixed religious household established in 31:19 (Laban\'s household gods). His attribution of his prosperity to YHWH, despite his use of divination, mirrors the theologically mixed character of the Aramaean household: recognizing YHWH\'s power while not fully abandoning other religious practices.</p>',

    "28": '<p>"Name your price, and I will pay it" — Laban\'s counter-offer to Jacob\'s departure request reopens the wage negotiation. Laban recognizes that Jacob\'s presence is the source of his prosperity (confirmed by divination, v.27) and is willing to pay to retain it. The offer puts Jacob in the position of naming his terms — which is precisely what Jacob needs in order to execute his breeding strategy in vv.32-42.</p>',

    "29": '<p>"You know how I have worked for you and how your livestock has fared under my care" — Jacob\'s negotiating position begins with an appeal to the observable record. His management of Laban\'s flocks has produced measurable prosperity; this is not a claim Laban can dispute (v.27 confirms he knows the flocks have done well). The appeal to observable results establishes Jacob\'s credibility before he makes his wage proposal.</p>',

    "30": '<p>"The little you had before I came has increased greatly, and the LORD has blessed you wherever I have been" — Jacob\'s attribution of Laban\'s prosperity to YHWH is a pointed theological claim: the blessing that follows Jacob is the Abrahamic covenant blessing (12:3 — those who bless Abraham are blessed). Laban has prospered not because of his own management but because YHWH is with Jacob. "But now, when am I going to do something for my own family?" — the shift to personal interest is direct; Jacob has spent fourteen years building Laban\'s household and nothing for his own.</p>',

    "31": '<p>"Don\'t give me anything. But if you will do this one thing for me, I will go on tending your flocks" — Jacob\'s proposal opens with a rhetorical disavowal of wanting anything, then specifies the one thing. This negotiating technique (appearing to ask for nothing while specifying a condition) is a recognized ANE and general human negotiating strategy. The proposal that follows — keeping only the abnormally colored animals — appears to give Laban a great advantage: the vast majority of Levantine sheep are white and goats are dark, so Jacob is seemingly claiming the minority exception animals.</p>',

    "32": '<p>"Let me go through all your flocks today and remove from them every speckled or spotted sheep, every dark-colored lamb and every spotted or speckled goat" — the specific categories Jacob requests — all abnormally colored animals — represented a small fraction of the normal flock. In Levantine pastoral genetics, white sheep and dark goats were the norm; speckled or spotted animals were exceptions. Jacob\'s wage proposal appears to favor Laban: he is asking for the rare, exceptional animals and leaving Laban the entire mainstream flock. The apparent generosity of the offer is what makes Laban agree.</p>',

    "33": '<p>"And my honesty will testify for me in the future, whenever you check on the wages you have paid me" — Jacob frames his proposal in terms of observable honesty: any spotted or speckled animal in his possession will have been born after the agreement, making the wage arrangement auditable. The word <em>ṣiḏqātî</em> (my righteousness/honesty) is Jacob invoking covenant vocabulary — his integrity can be verified by inspection. The irony is that Jacob\'s "honest" proposal is accompanied by a breeding strategy that will systematically generate abnormal offspring.</p>',

    "34": '<p>"Agreed. Let it be as you have said" — Laban\'s prompt agreement signals that he believes he has the better end of the deal. He has just secured more free labor from Jacob and given away only the animals he did not want to start with. The brevity of his assent (<em>lûʾ</em>, very well, if only) mirrors the confidence of a man who thinks he cannot lose.</p>',

    "35": '<p>"That same day he removed all the male goats that were streaked or spotted, and all the speckled or spotted female goats — all that had white on them — and all the dark-colored lambs, and he had them tended by his sons" — Laban immediately moves to prevent Jacob from having access to the parent animals whose genetic traits might produce spotted offspring. By removing all already-spotted animals from the common flock on the very day of the agreement, Laban attempts to make it genetically impossible for Jacob\'s agreed wage (spotted/speckled animals) to be produced naturally from the remaining white and dark animals.</p>',

    "36": '<p>"Then he put a three-day journey between himself and Jacob, while Jacob continued to tend the rest of Laban\'s flocks" — the three-day separation of the removed animals from Jacob\'s management is a calculated buffer. With the spotted animals physically isolated (under his sons\' care) and three days\' journey away, Laban expects Jacob will have no access to the genetic source material needed to produce his agreed wages. The physical separation is Laban\'s counter-move against Jacob\'s breeding strategy — except that Jacob\'s strategy does not depend on access to the separated animals.</p>',

    "37": '<p>"Jacob took fresh-cut branches from poplar, almond and plane trees and made white stripes on them by peeling the bark and exposing the white inner wood of the branches" — Jacob\'s technique reflects ANE folk genetics: the belief that what a pregnant animal (or woman) saw during conception influenced the appearance of the offspring. This belief appears in later ANE and Hellenistic texts (Aristotle mentions it; Roman agricultural writers discuss it). The three tree types — poplar (<em>libneh</em>, white), almond (<em>lûz</em>, perhaps connected to Bethel/Luz of 28:19), plane (<em>ʿermôn</em>) — produce visually striped branches when peeled.</p>',

    "38": '<p>"He placed the peeled branches in all the watering troughs, so that they would be directly in front of the flocks when they came to drink. When the flocks were in heat and came to drink, they mated in front of the branches" — the connection between the watering place (where the flocks came in heat) and the visual stimulation of the striped branches is the mechanism of the folk-genetic technique. ANE pastoral practice recognized that the combination of the watering visit and mating were often simultaneous. The strategy targets the moment of conception as the window for visual influence.</p>',

    "39": '<p>"They mated in front of the branches. And they bore young that were streaked or speckled or spotted" — the technique appears to work. The narrator presents the outcome without editorial comment on whether the branches caused the coloration or YHWH intervened. Gen 31:10-12 provides the narrative key: Jacob will later tell Rachel that a divine dream revealed the true mechanism — it was God, not the branches, selecting which rams bred with the flock. The branches were Jacob\'s human technique; the dream-revelation clarifies that divine guidance was the actual cause.</p>',

    "40": '<p>"Jacob set apart the young of the flock and had the flocks face in the direction of the streaked and dark-colored animals that belonged to Laban. This way he made separate flocks for himself and did not put them with Laban\'s animals" — Jacob manages the selective breeding by directing his newly born spotted flock to mate among themselves (facing the direction of Laban\'s streaked animals as a visual influence), while keeping them separate from Laban\'s mainstream flock. The separation prevents the spotted offspring from being mixed back into Laban\'s white flock, where they would lose their distinguishing markers.</p>',

    "41": '<p>"Whenever the stronger females were in heat, Jacob would place the branches in the troughs in front of the animals so they would mate near the branches" — Jacob applies the branch technique selectively: only when the stronger, healthier animals are mating. The distinction between strong and weak animals in the breeding strategy ensures that the most genetically robust offspring will become Jacob\'s wage, while the weaker stock goes to Laban. This is not random but calculated selective breeding for quality.</p>',

    "42": '<p>"But if the animals were weak, he would not place the branches there. So the weak animals went to Laban and the strong ones to Jacob" — the selective application of the technique produces a systematic quality advantage for Jacob: his flock receives the offspring of the strongest parents, while Laban\'s flock accumulates the offspring of weaker parents. Over time, Jacob\'s flock quality would increase while Laban\'s would decline — independent of the color-marking scheme. The two effects (color selection and quality selection) compound Jacob\'s advantage.</p>',

    "43": '<p>"The man grew exceedingly prosperous and came to own large flocks, and female and male servants, and camels and donkeys" — Jacob\'s final prosperity inventory mirrors Abraham\'s wealth summary in 12:16 and 24:35: sheep, servants, camels, and donkeys are the standard ANE markers of a wealthy household. The phrase <em>wayyipreṣ hāʾîš mĕʾōḏ mĕʾōḏ</em> (the man increased exceedingly exceedingly) — double intensification — marks Jacob\'s prosperity as exceptional. The covenant blessing promised in 28:13-15 (land, offspring, divine presence) is being realized in the material dimension even before Jacob returns to the promised land.</p>',
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-context', 'genesis', existing)
    print('Genesis 29-30 mkt-context written.')

if __name__ == '__main__':
    main()
